/*
  Persists textarea content to localStorage so exercise notes survive a reload.

  Markup contract:
  <textarea class="scratchpad" data-scratchpad="unique-key" placeholder="…"></textarea>

  Keys should be unique per-lesson (e.g. "0001-notification-refactor") to avoid
  collisions across lessons sharing the same browser storage.
*/
(function () {
  var PREFIX = "teach-scratchpad:";

  function initPad(el) {
    var key = PREFIX + el.getAttribute("data-scratchpad");
    var saved = window.localStorage.getItem(key);
    if (saved) el.value = saved;

    el.addEventListener("input", function () {
      window.localStorage.setItem(key, el.value);
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    Array.prototype.forEach.call(document.querySelectorAll("[data-scratchpad]"), initPad);
  });
})();
